raw:
{
  "qa_list": [
    {
      "q": "텍스트 기반 추론형 AI 데이터셋의 구성 방식과 진화 방향은 어떠합니까?",
      "a": "텍스트 기반 추론형 AI 데이터셋은 LLM의 논리적 사고와 문제 해결 능력 강화를 위해 질문-추론-답변 구조로 구성됩니다. 진화 방향으로는 일반 상식과 기초 수학 문제를 넘어 점차 고난이도화되고, 메타-추론이나 전문가 수준 문제를 풀 수 있는 방향으로 발전하고 있습니다.",
      "intent": "fact",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '텍스트 기반 추론형 AI 데이터셋은 LLM의 논리적 사고와 문제 해결 능력 강화를 위해 질문-추론-답변 구조로 구성되며, 일반 상식과 기초 수학 문제를 넘어 점차 고난이도화되고, 메타-추론이나 전문가 수준 문제를 풀 수 있는 방향으로 진화하고 있습니다'에 직접 근거.",
        "2) 질문 구성 방식 — 데이터셋의 구성 구조(질문-추론-답변)와 진화 방향(고난이도화, 메타-추론, 전문가 수준)이라는 두 가지 요소를 동일한 'fact' 차원에서 질문으로 구성."
      ],
      "answerable": true
    },
    {
      "q": "멀티모달 추론 데이터셋이 추구하는 목적은 무엇입니까?",
      "a": "멀티모달 추론 데이터셋은 AI 모델이 텍스트, 이미지, 비디오 등 여러 양식의 정보를 동시에 이해하고 종합하여 복잡한 결론을 도출하도록 도와 인간과 유사한 인지 능력을 갖도록 하는 데 목적이 있습니다.",
      "intent": "purpose",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '멀티모달 추론 데이터셋은 AI 모델이 텍스트, 이미지, 비디오 등 여러 양식의 정보를 동시에 이해하고 종합하여 복잡한 결론을 도출하도록 도와 인간과 유사한 인지 능력을 갖도록 하는 데 목적이 있습니다'에 '목적이 있습니다'라는 명시적 목적 문구가 있어 purpose 유형 적용 가능.",
        "2) 질문 구성 방식 — 컨텍스트에 명시적으로 기술된 목적(여러 양식 정보 통합 이해, 복잡한 결론 도출, 인간 유사 인지 능력 구현)을 단일 purpose 차원에서 질문으로 구성."
      ],
      "answerable": true
    },
    {
      "q": "텍스트 기반 추론형 AI 데이터셋과 멀티모달 추론 데이터셋이 각각 다루는 정보 범위는 어떻게 구분됩니까?",
      "a": "텍스트 기반 추론형 AI 데이터셋은 LLM의 논리적 사고와 문제 해결 능력 강화를 위해 질문-추론-답변 구조로 구성되며, 일반 상식 및 기초 수학 문제부터 메타-추론 및 전문가 수준 문제까지를 다룹니다. 반면 멀티모달 추론 데이터셋은 텍스트에 국한되지 않고 이미지, 비디오 등 여러 양식의 정보를 동시에 포함하며, 이를 종합하여 복잡한 결론을 도출하는 데 초점을 맞춥니다.",
      "intent": "comparison",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — 텍스트 기반 데이터셋의 정보 범위는 '질문-추론-답변 구조', '일반 상식과 기초 수학 문제~고난이도·메타-추론·전문가 수준'으로 명시되어 있으며, 멀티모달 데이터셋의 정보 범위는 '텍스트, 이미지, 비디오 등 여러 양식'으로 명시되어 있어 두 대상 모두 컨텍스트에 근거가 있음.",
        "2) 질문 구성 방식 — 두 데이터셋 유형이 다루는 정보 범위라는 동일 속성(P7 대칭 검증 충족)을 비교하는 단일 comparison 차원으로 구성."
      ],
      "answerable": true
    }
  ]
}

